--
-- Migration: Update all law sources from BLHS abbreviations to full "Bộ luật Hình sự" names
-- Date: 2026-04-13
-- Purpose: Normalize law source names for better user clarity and system consistency
--

BEGIN TRANSACTION;

-- Update BLHS 1999
UPDATE laws SET source = 'Bộ luật Hình sự 1999' WHERE source = 'BLHS 1999';

-- Update BLHS 2009 variants
UPDATE laws SET source = 'Bộ luật Hình sự 2009 (sửa đổi)' WHERE source = 'BLHS 2009 (sửa đổi)';
UPDATE laws SET source = 'Bộ luật Hình sự 2009' WHERE source = 'BLHS 2009';

-- Update BLHS 2015 variants
UPDATE laws SET source = 'Bộ luật Hình sự 2015 (sửa đổi 2017)' WHERE source = 'BLHS 2015 (sửa đổi 2017)';
UPDATE laws SET source = 'Bộ luật Hình sự 2015' WHERE source = 'BLHS 2015';

-- Update BLHS 2025
UPDATE laws SET source = 'Bộ luật Hình sự 2025' WHERE source = 'BLHS 2025';

COMMIT;

-- Verify the updates
SELECT DISTINCT source FROM laws ORDER BY source;


